args.query:
SELECT oldvalue__c AS from_owner, newvalue__c AS to_owner, createddate
FROM casehistory__c
WHERE field__c = 'Owner' AND createddate >= '2022-04-10' AND createddate < '2023-04-11' AND oldvalue__c IS NOT NULL;

